import { initTRPC } from "@trpc/server";
import { z } from "zod";

/**
 * Initialise tRPC.
 * We keep the context empty for this example; extend it with
 * session / database handles as needed.
 */
const t = initTRPC.create();

export const router = t.router;
export const publicProcedure = t.procedure;

/**
 * Application router ã add all procedures here.
 */
export const appRouter = router({
  /**
   * addMessage ã accepts a non-empty text string and echoes it back
   * together with a success flag.
   */
  addMessage: publicProcedure
    .input(z.object({ text: z.string().min(1, "Message cannot be empty") }))
    .mutation(async ({ input }) => {
      // In a real application you would persist the message here
      // (e.g. database insert, message-queue publish, ãÎ).
      return { success: true as const, message: input.text };
    }),
});

// Export the type of the router so the client stays in sync
export type AppRouter = typeof appRouter;

/**
 * createCallerFactory lets us call tRPC procedures directly from the
 * server without going through HTTP ã perfect for Server Actions.
 */
export const createCaller = t.createCallerFactory(appRouter);

"use server";

import { createCaller } from "@/server/trpc";

/**
 * Server Action: addMessage
 *
 * Creates a tRPC caller via `createCallerFactory` and invokes the
 * `addMessage` mutation entirely on the server ã no HTTP round-trip.
 *
 * @param text - The message text submitted from the client form.
 * @returns    The procedure result: { success: true, message: string }
 */
export async function addMessage(
  text: string,
): Promise<{ success: true; message: string }> {
  // Instantiate a server-side caller (context can be extended later,
  // e.g. to forward cookies / auth headers).
  const caller = createCaller({});

  // Directly invoke the tRPC mutation ã fully type-safe.
  const result = await caller.addMessage({ text });

  return result;
}

